// ─── Build the Claude prompt from all discovery form fields ─────────────────
const d = $input.first().json.body;

// Vertical playbooks for pitch suggestions
const VERTICAL_PLAYBOOKS = {
  'Real Estate': {
    starter: ['Instant lead response (speed-to-lead SMS)', 'Missed call → auto SMS', '7-touch cold nurture sequence'],
    growth: ['SOI re-engagement campaign', 'Open house follow-up sequence'],
    pro: ['MLS feed → lead scoring dashboard', 'Deal velocity reporting']
  },
  'Dental / Medical': {
    starter: ['Appointment reminder sequence (48hr + 2hr)', 'Missed appointment follow-up', 'Post-visit review request'],
    growth: ['Dormant patient reactivation', 'New patient welcome sequence'],
    pro: ['Dentrix/Eaglesoft → production dashboard', 'No-show risk scoring']
  },
  'Insurance': {
    starter: ['Renewal reminders (90/60/30/7 days)', 'Post-renewal thank you + review request', 'Quote request auto-response'],
    growth: ['Cross-sell campaign', 'Lapsed policy win-back'],
    pro: ['Book-of-business pipeline', 'Retention risk scoring']
  },
  'default': {
    starter: ['Missed call → auto SMS', 'Lead response within 5 minutes', 'Post-service review request'],
    growth: ['Client reactivation campaign', 'Referral follow-up sequence'],
    pro: ['Custom intake pipeline', 'Client retention dashboard']
  }
};

const industry = d.industry || '';
const playbooks = VERTICAL_PLAYBOOKS[industry] || VERTICAL_PLAYBOOKS['default'];

// Tier determination hints based on volume and hours
const leadsPerMonth = parseInt(d.leads_per_month) || 0;
const adminHours = d.admin_hours_per_week || '';
const timeline = d.timeline || '';
const revenue = d.revenue_range || '';

const prompt = `You are Egan's AI research assistant at Norr AI, an automation agency serving local businesses. A prospect just completed a discovery questionnaire. Your job is to analyze their situation and give Egan everything he needs to have an excellent first call — a clear tier recommendation, the right workflows to pitch, and a personalized opener.

Here is the completed discovery form:

## WHO THEY ARE
Name: ${d.contact_name || 'Not provided'}
Business: ${d.business_name || 'Not specified'}
Industry: ${industry || 'Not specified'}
Team size: ${d.team_size || 'Not specified'}
Email: ${d.contact_email || 'Not provided'}
Phone: ${d.contact_phone || 'Not provided'}

## WHAT BROUGHT THEM HERE
${d.what_brings_you || 'Not provided'}

## PAIN RATINGS (1 = barely any · 5 = major pain)
Speed of response to new leads: ${d.pain_missed_leads !== null && d.pain_missed_leads !== undefined ? d.pain_missed_leads + '/5' : 'Not rated'}
Time spent on manual follow-up: ${d.pain_manual_followup !== null && d.pain_manual_followup !== undefined ? d.pain_manual_followup + '/5' : 'Not rated'}
No-shows or missed appointments: ${d.pain_no_shows !== null && d.pain_no_shows !== undefined ? d.pain_no_shows + '/5' : 'Not rated'}
Asking clients for reviews: ${d.pain_review_requests !== null && d.pain_review_requests !== undefined ? d.pain_review_requests + '/5' : 'Not rated'}
Repetitive admin / data entry: ${d.pain_admin_time !== null && d.pain_admin_time !== undefined ? d.pain_admin_time + '/5' : 'Not rated'}
Inconsistent client communication: ${d.pain_inconsistent_comms !== null && d.pain_inconsistent_comms !== undefined ? d.pain_inconsistent_comms + '/5' : 'Not rated'}

Biggest pain (in their words): ${d.biggest_pain || 'Not provided'}

## CURRENT TOOLS
CRM: ${d.current_crm || 'Not specified'}
Scheduling: ${d.scheduling_tool || 'Not specified'}
Communication channels: ${d.comms_channels || 'Not specified'}
Has website: ${d.has_website || 'Not specified'}

## VOLUME & SCALE
Leads per month: ${d.leads_per_month || 'Not specified'}
Clients per month: ${d.clients_per_month || 'Not specified'}
Admin hours per week: ${adminHours || 'Not specified'}
Annual revenue: ${revenue || 'Not specified'}

## PRIORITIES
Timeline: ${timeline || 'Not specified'}
Tried automation before: ${d.tried_automation_before || 'Not specified'}
${d.automation_experience ? 'Prior automation experience: ' + d.automation_experience : ''}

What success looks like:
${d.success_looks_like || 'Not provided'}

Anything else:
${d.anything_else || 'None'}

---

Known workflow options for ${industry || 'this vertical'}:
- Starter tier ($500–600/mo): ${playbooks.starter.join(', ')}
- Growth tier ($1,000–1,200/mo): ${playbooks.growth.join(', ')}
- Pro tier ($2,000–2,500/mo): ${playbooks.pro.join(', ')}

---

Produced a structured analysis with exactly these sections:

**SITUATION SUMMARY**
3 sentences. What's really going on for this prospect — the operational reality behind their pain ratings, what they're losing today by not having automation, and what the highest-stakes risk is if nothing changes. Make it feel like you've been listening, not just reading a form.

**RECOMMENDED TIER**
Starter, Growth, or Pro — with a one-sentence rationale. Base this on: their volume, admin hours, timeline urgency, and the complexity of their highest-rated pains. If they're borderline between tiers, say so and explain why.

**TOP 2–3 WORKFLOWS TO PITCH**
For each, include:
- Name of the workflow
- The specific pain it addresses (cite their rating or their exact words)
- What it does in plain language
- Expected ROI framing in their industry's language (dentists think in appointment values, realtors in GCI, insurance in retained premium)

Rank them by impact-to-effort ratio for this specific prospect — not by what's generally most popular.

**PERSONALIZED CALL OPENER FOR EGAN**
A 2–3 sentence opener Egan can use at the top of the discovery call. It should reference something specific they said, acknowledge the real pain, and tee up the conversation without pitching anything yet. Sound like a human who read their form carefully, not an AI summary.

**STACK NOTES**
Brief. What will integrate easily given their current tools, what will need a workaround, and anything worth clarifying on the call.

Be direct and specific. Use their exact words where it makes the point stronger.`;

const claude_request_body = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 2048,
  messages: [{ role: 'user', content: prompt }]
});

return [{
  json: {
    prompt,
    claude_request_body,
    contact_name: d.contact_name || 'Unknown',
    contact_email: d.contact_email || '',
    business_name: d.business_name || 'Unknown Business',
    industry: industry,
    submitted_at: d.submitted_at || new Date().toISOString()
  }
}];

// ─── Extract Claude's analysis and format email ─────────────────────────────
const claudeResponse = $input.first().json;
const analysis = claudeResponse.content?.[0]?.text ?? 'No response from Claude.';

const contactName  = $('Build Claude Prompt').first().json.contact_name;
const contactEmail = $('Build Claude Prompt').first().json.contact_email;
const businessName = $('Build Claude Prompt').first().json.business_name;
const industry     = $('Build Claude Prompt').first().json.industry;
const submittedAt  = $('Build Claude Prompt').first().json.submitted_at;

const formattedTime = new Date(submittedAt).toLocaleString('en-US', { timeZone: 'America/Chicago', hour12: true });

const htmlAnalysis = analysis
  .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
  .replace(/\n\n/g, '</p><p style="margin:0 0 14px">')
  .replace(/\n/g, '<br>');

const htmlBody = `
<div style="font-family: 'Inter', -apple-system, sans-serif; max-width: 720px; margin: 0 auto; color: #0A0F1A;">
  <div style="background: #0A0F1A; padding: 32px; border-radius: 8px 8px 0 0;">
    <div style="font-family: monospace; font-size: 10px; letter-spacing: 0.2em; text-transform: uppercase; color: #7FA9B8; margin-bottom: 8px;">Norr AI · Discovery Analysis</div>
    <div style="font-family: 'Inter Tight', sans-serif; font-weight: 700; font-size: 22px; color: #FAFAF7; letter-spacing: -0.03em;">${contactName} · ${businessName}</div>
    <div style="font-size: 12px; color: #6A6F78; margin-top: 6px;">${industry} · Submitted ${formattedTime} CT · <a href="mailto:${contactEmail}" style="color:#7FA9B8;">${contactEmail}</a></div>
  </div>
  <div style="background: #FAFAF7; border: 1px solid #E5E4DE; border-top: none; border-radius: 0 0 8px 8px; padding: 32px;">
    <p style="margin: 0 0 14px; font-size: 14px; line-height: 1.75; color: #3A3F48;">${htmlAnalysis}</p>
  </div>
  <div style="text-align: center; padding: 24px; font-size: 11px; color: #9EA3AA; font-family: monospace; letter-spacing: 0.1em;">NORR AI · FARIBAULT, MN · AUTOMATED DISCOVERY ANALYSIS</div>
</div>
`;

return [{
  json: {
    analysis,
    html_body: htmlBody,
    contact_name: contactName,
    contact_email: contactEmail,
    business_name: businessName,
    subject: `Discovery: ${contactName} — ${businessName} (${industry})`
  }
}];
